package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

class ReflectionHelperTest {

  // Declare an interface matching RecordHelper methods needed for mocking
  interface RecordHelper {
    String[] getRecordComponentNames(Class<?> raw);
  }

  private static RecordHelper recordHelperMock;

  @BeforeAll
  static void setup() throws Exception {
    recordHelperMock = mock(RecordHelper.class);

    Field field = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    field.setAccessible(true);

    // Remove final modifier
    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(field, field.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

    field.set(null, recordHelperMock);
  }

  @Test
  void testGetRecordComponentNames_returnsNamesFromRecordHelper() {
    String[] expected = new String[] {"component1", "component2"};
    Class<?> recordClassMock = String.class;

    when(recordHelperMock.getRecordComponentNames(recordClassMock)).thenReturn(expected);

    String[] actual = ReflectionHelper.getRecordComponentNames(recordClassMock);

    assertArrayEquals(expected, actual);
    verify(recordHelperMock).getRecordComponentNames(recordClassMock);
  }

  @Test
  void testGetRecordComponentNames_nullClass_throwsNPE() {
    when(recordHelperMock.getRecordComponentNames(null)).thenThrow(NullPointerException.class);

    assertThrows(NullPointerException.class, () -> ReflectionHelper.getRecordComponentNames(null));
    verify(recordHelperMock).getRecordComponentNames(null);
  }
}
